// Verkäufer mit HubSpot Owner IDs und Halleluja-OS Person IDs
// ⚠️ ANPASSEN: pid muss mit euren Supabase personen.id übereinstimmen!
const VERKÄUFER = [
  { name: 'Dominik', ownerId: '30037585', pid: 'DOMINIK_PID_HIER' },
  { name: 'Gülser', ownerId: '30074150', pid: 'GÜLSER_PID_HIER' },
  { name: 'Dominic W.', ownerId: '30463715', pid: 'DOMINIC_PID_HIER' },
];

return VERKÄUFER.map(v => ({ json: v }));

const STAGES = {
  '874823135': 'Lead',
  '1810218174': 'Setting FollowUp',
  '1810218175': 'Call vereinbart',
  '140299275': 'Goldstandard',
  '16380590': 'Closing FollowUp',
  '874823137': 'Closing Call 1',
  '70811040': 'Closing Call 2',
  '2622716091': 'Closing Call 3',
  '5055646918': 'Rechnungsentwurf',
  '1761746124': 'Rechnung'
};

const verkäufer = $('Verkäufer-Liste').first().json;
const deals = $json.results || [];
const total = $json.total || 0;
const today = new Date().toISOString().slice(0, 10);
const sevenDaysAgo = new Date(Date.now() - 7 * 86400000).toISOString();

const stageCounts = {};
let todayNew = 0;
let overdue = 0;

deals.forEach(d => {
  const stage = d.properties.dealstage;
  stageCounts[stage] = (stageCounts[stage] || 0) + 1;
  if ((d.properties.createdate || '').slice(0, 10) === today) todayNew++;
  const lc = d.properties.notes_last_contacted;
  if (!lc || lc < sevenDaysAgo) overdue++;
});

const pipeStr = Object.entries(STAGES)
  .filter(([id]) => stageCounts[id])
  .map(([id, label]) => `${label}: ${stageCounts[id]}`)
  .join(', ');

const zusammenfassung = `${verkäufer.name}: ${total} offene Deals (${pipeStr}). ` +
  `Heute neu: ${todayNew}. Überfällig (>7d): ${overdue}.`;

return [{
  json: {
    id: 'kf-hubspot-' + verkäufer.pid + '-' + today,
    pid: verkäufer.pid,
    quelle: 'hubspot',
    typ: 'pipeline-person',
    zusammenfassung,
    rohdaten: { stageCounts, total, todayNew, overdue },
    relevanz: overdue > 10 ? 'hoch' : 'mittel',
    created_at: new Date().toISOString(),
    gueltig_bis: today
  }
}];
